VALUES
  ('optician-moex-02289', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '當配戴眼鏡的度數為遠視+3.00 DS（頂點距離12 mm），要換算成軟式隱形眼鏡，下列何者為最接近適合 的度數？', '["+2.50 DS", "+2.75 DS", "+3.00 DS", "+3.50 DS"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02290', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關硬式透氣隱形眼鏡（RGP）的邊弧（peripheral curve）設計和功能作用，下列敘述何者錯誤？', '["可避免鏡片滑動時邊緣傷害眼角膜", "可提供淚液交換", "可協助穩定鏡片中央定位", "可提供光學矯正功能"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02291', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '使用試戴片（度數-3.00DS）驗配高透氣硬式隱形眼鏡，達理想配戴，而插片驗光視力達 1.0 的度數為 -4.50DS/-0.75DC×180，頂點距離為12 mm，則訂片的屈光度數最接近為：', '["-4.50 DS", "-5.00 DS", "-7.50 DS", "-8.00 DS"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02292', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '若增大硬式透氣隱形眼鏡鏡片直徑（overall lens diameter, OAD）及中央光學區直徑（optic zone diameter, OZD）而不改變中心基弧（base curve radius），對鏡片矢深（sagittal depth）及頂點間隙（apical clearance） 影響為何？', '["兩者皆增加", "兩者皆減少", "前者增加後者減少", "前者減少後者增加"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02293', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '眼鏡的處方為-8.75DS/-3.25DC×180（頂點距離為12 mm），則軟式隱形眼鏡處方應為：', '["-8.00DS/-3.25DC×180", "-8.00DS/-2.50DC×180", "-8.75DS/-3.25DC×180", "-8.00DS/-3.00DC×180"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02294', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關隱形眼鏡之Dk值，下列敘述何者錯誤？', '["D表示氧氣分子在某鏡片材質內的擴散係數", "k表示氧氣分子在某鏡片材質內的溶解係數", "Dk表示氧氣分子在某鏡片材質的透氧率", "角膜獲得氧氣的能力取決於Dk參數，鏡片厚度影響甚微，可忽略不考慮"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02295', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '下列那一方式無法減少隱形眼鏡配戴後之角膜新生血管機會？', '["改用透氧性較高材質鏡片", "改用較緊鏡片", "減少每日配戴時間", "改用拋棄式鏡片"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02296', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '一眼屈光是-5.00DS/-0.25DC×180，角膜弧度是H：42.50D@180/V：44.00D@090，配戴那一種隱形眼鏡 可達到較佳之視力品質？', '["軟式散光隱形眼鏡（soft toric）", "軟式球面隱形眼鏡（soft spherical）", "硬式透氣球面隱形眼鏡（spherical GP）", "硬式透氣前散光設計隱形眼鏡（front toric GP）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02297', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '驗配隱形眼鏡時，若試戴片在角膜上黏住不動，下列那項處理最恰當？', '["調整基弧變成更平，維持原試戴片直徑", "維持原基弧，增大試戴片直徑", "調整基弧變成更彎曲，維持原試戴片直徑", "減少隱形眼鏡度數"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-02298', 'optician', 'optician-moex-107-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '硬式隱形眼鏡鏡片重心會影響鏡片在角膜上的附著力，有關鏡片與重心（center of gravity）的關係，下列 敘述何者正確？', '["增加鏡片的直徑，可使重心偏往角膜之前方（forward）", "正屈光度的鏡片，重心會偏往角膜之前方", "基弧較平的鏡片，重心會偏往角膜之後方（posterior）", "較薄的鏡片，可使重心偏往角膜之前方"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:36+00:00", "source_pdf_sha1": "5f2c5edd9a35", "answer_pdf_sha1": "fbaba87199f7", "source_family": "moex-gov-tw", "moex": {"exam_code": "107060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "107", "exam_name": "107年專技人員高等考試大地工程技師考試分階段考試、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政士、專責報關人員...", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
